#include <iostream>
#include <algorithm>
using namespace std;
int a[999];
int main()
{
    int n,x,count=0;
    cin>>n>>x;
    while(n!=0)
    {
        count++;
        a[count]=n%x;
        n/=x;
    }
    for(int i=count;i>=1;i--)
    {
        if(a[i]>=10)
        {
            cout<<(char)(a[i]+55);
        }
        else
        {
            cout<<a[i];
        }
    }
    return 0;
}
